  1→/**
  2→ * Anthropic LLM Proxy Route
  3→ *
  4→ * Transparent proxy that forwards requests to Anthropic's Messages API
  5→ * with identity resolution, session tracking, and workspace validation.
  6→ *
  7→ * Pipeline execution order:
  8→ * 1. Identity resolution (from metadata + headers)
  9→ * 2. Session ID resolution (header priority over metadata)
 10→ * 3. Conversation hash (03-01) — deterministic UUIDv5 from content
 11→ * 4. Policy evaluation [future 02-01]
 12→ * 5. Context injection [future 03-02]
 13→ * 6. Request forwarding
 14→ * 7. Async trace capture (01-03) + conversation upsert
 15→ */
 16→import { logInfo, logError, logWarn, elapsedMs } from "../http/observability";
 17→import { jsonResponse } from "../http/response";
 18→import { resolveIdentity } from "./identity-resolver";
 19→import { resolveSessionId, resolveAgentSessionId } from "./session-id-resolver";
 20→import { captureTrace, type TraceData } from "./trace-writer";
 21→import {
 22→  resolveConversationHash,
 23→  type ConversationHashInput,
 24→} from "./conversation-hash-resolver";
 25→import { upsertConversation } from "./conversation-upserter";
 26→import {
 27→  evaluateProxyPolicy,
 28→  type ProxyPolicyDependencies,
 29→  type ProxyPolicyResult,
 30→  type PolicyDecisionLog,
 31→  type SpendCache,
 32→} from "./policy-evaluator";
 33→import {
 34→  createRateLimiterState,
 35→  pruneStaleEntries,
 36→  type RateLimiterState,
 37→} from "./rate-limiter";
 38→import {
 39→  loadIntelligenceConfig,
 40→  type IntelligenceConfig,
 41→} from "./intelligence-config";
 42→import {
 43→  createContextCache,
 44→  type ContextCache,
 45→  type CachedCandidatePool,
 46→  type CandidateItem,
 47→} from "./context-cache";
 48→import {
 49→  rankCandidates,
 50→  selectWithinBudget,
 51→  buildBrainContextXml,
 52→  injectBrainContext,
 53→  type ContextCandidate,
 54→  type InjectionResult,
 55→} from "./context-injector";
 56→import type { ServerDependencies } from "../runtime/types";
 57→import { RecordId } from "surrealdb";
 58→
 59→const FORWARDED_HEADERS = [
 60→  "anthropic-version",
 61→  "anthropic-beta",
 62→  "content-type",
 63→] as const;
 64→
 65→// ---------------------------------------------------------------------------
 66→// Workspace Validation (cached)
 67→// ---------------------------------------------------------------------------
 68→
 69→type WorkspaceCache = Map<string, { valid: boolean; checkedAt: number }>;
 70→
 71→const WORKSPACE_CACHE_TTL_MS = 60_000; // 1 minute
 72→
 73→async function validateWorkspace(
 74→  surreal: ServerDependencies["surreal"],
 75→  workspaceId: string,
 76→  cache: WorkspaceCache,
 77→): Promise<boolean> {
 78→  const cached = cache.get(workspaceId);
 79→  if (cached && Date.now() - cached.checkedAt < WORKSPACE_CACHE_TTL_MS) {
 80→    return cached.valid;
 81→  }
 82→
 83→  try {
 84→    const results = await surreal.query<[Array<{ id: RecordId }>]>(
 85→      `SELECT id FROM $ws;`,
 86→      { ws: new RecordId("workspace", workspaceId) },
 87→    );
 88→    const valid = (results[0]?.length ?? 0) > 0;
 89→    cache.set(workspaceId, { valid, checkedAt: Date.now() });
 90→    return valid;
 91→  } catch {
 92→    cache.set(workspaceId, { valid: false, checkedAt: Date.now() });
 93→    return false;
 94→  }
 95→}
 96→
 97→// ---------------------------------------------------------------------------
 98→// Header Forwarding
 99→// ---------------------------------------------------------------------------
100→

 1→/**
 2→ * Conversation Upserter — Idempotent DB Adapter
 3→ *
 4→ * Creates or updates a conversation record in SurrealDB using native UPSERT
 5→ * with the deterministic UUIDv5 conversation ID from the hash resolver.
 6→ *
 7→ * Port: (ConversationUpsertInput, Dependencies) -> Promise<RecordId | undefined>
 8→ * Side effects: SurrealDB writes (boundary adapter)
 9→ */
10→
11→import { RecordId } from "surrealdb";
12→import type { Surreal } from "surrealdb";
13→import { logInfo, logError } from "../http/observability";
14→
15→// ---------------------------------------------------------------------------
16→// Types
17→// ---------------------------------------------------------------------------
18→
19→export type ConversationUpsertInput = {
20→  readonly conversationId: string;
21→  readonly workspaceId: string;
22→  readonly title: string;
23→};
24→
25→type ConversationUpsertDependencies = {
26→  readonly surreal: Surreal;
27→};
28→
29→// ---------------------------------------------------------------------------
30→// Public API
31→// ---------------------------------------------------------------------------
32→
33→/**
34→ * Upsert a conversation record. Returns the RecordId on success,
35→ * undefined on failure. Failure never throws -- it logs a warning
36→ * and returns undefined so the caller can proceed without blocking.
37→ */
38→export async function upsertConversation(
39→  input: ConversationUpsertInput,
40→  deps: ConversationUpsertDependencies,
41→): Promise<RecordId | undefined> {
42→  const conversationRecord = new RecordId("conversation", input.conversationId);
43→  const workspaceRecord = new RecordId("workspace", input.workspaceId);
44→
45→  try {
46→    const results = await deps.surreal.query<[Array<{ id: RecordId }>]>(
47→      `UPSERT $conversation MERGE {
48→        workspace: $workspace,
49→        title: $title,
50→        title_source: "message",
51→        source: "proxy",
52→        createdAt: createdAt ?? time::now(),
53→        updatedAt: time::now()
54→      };`,
55→      {
56→        conversation: conversationRecord,
57→        workspace: workspaceRecord,
58→        title: input.title,
59→      },
60→    );
61→
62→    const record = results[0]?.[0];
63→    if (record) {
64→      logInfo("proxy.conversation.upserted", "Proxy conversation upserted", {
65→        conversation_id: input.conversationId,
66→        workspace_id: input.workspaceId,
67→      });
68→      return record.id;
69→    }
70→  } catch (error) {
71→    logError(
72→      "proxy.conversation.upsert_failed",
73→      "Failed to upsert conversation record",
74→      error,
75→    );
76→  }
77→
78→  return undefined;
79→}
80→

  1→/**
  2→ * Conversation Hash Resolver — Pure Function
  3→ *
  4→ * Derives a deterministic conversation identity from request content
  5→ * using UUIDv5(BRAIN_PROXY_NAMESPACE, system_prompt + NUL + first_user_message).
  6→ *
  7→ * This enables trace grouping across multiple turns of the same conversation
  8→ * without requiring Brain integration or session lifecycle management.
  9→ *
 10→ * Port: ConversationHashInput -> ConversationHashResult | undefined
 11→ * Side effects: none (pure function)
 12→ */
 13→
 14→import { createHash } from "crypto";
 15→
 16→// ---------------------------------------------------------------------------
 17→// UUIDv5 Namespace for Brain Proxy
 18→// ---------------------------------------------------------------------------
 19→
 20→/** Brain proxy namespace UUID for UUIDv5 generation (randomly generated, fixed). */
 21→const BRAIN_PROXY_NAMESPACE = "a1b2c3d4-e5f6-4a7b-8c9d-0e1f2a3b4c5d";
 22→
 23→/** NUL separator between system prompt and first user message. */
 24→const NUL_SEPARATOR = "\0";
 25→
 26→/** Maximum title length before truncation. */
 27→const MAX_TITLE_LENGTH = 100;
 28→
 29→// ---------------------------------------------------------------------------
 30→// Types
 31→// ---------------------------------------------------------------------------
 32→
 33→export type ConversationHashInput = {
 34→  readonly systemPrompt?: string;
 35→  readonly systemPromptBlocks?: ReadonlyArray<{ type: string; text: string }>;
 36→  readonly messages: ReadonlyArray<{ role: string; content: string }>;
 37→};
 38→
 39→export type ConversationHashResult = {
 40→  readonly conversationId: string;
 41→  readonly title: string;
 42→};
 43→
 44→// ---------------------------------------------------------------------------
 45→// UUIDv5 Implementation (RFC 4122)
 46→// ---------------------------------------------------------------------------
 47→
 48→function namespaceToBytes(namespaceUuid: string): Buffer {
 49→  const hex = namespaceUuid.replace(/-/g, "");
 50→  return Buffer.from(hex, "hex");
 51→}
 52→
 53→function generateUuidV5(namespace: string, name: string): string {
 54→  const namespaceBytes = namespaceToBytes(namespace);
 55→  const nameBytes = Buffer.from(name, "utf-8");
 56→
 57→  const hashInput = Buffer.concat([namespaceBytes, nameBytes]);
 58→  const hash = createHash("sha1").update(hashInput).digest();
 59→
 60→  // Set version to 5 (bits 4-7 of byte 6)
 61→  hash[6] = (hash[6] & 0x0f) | 0x50;
 62→
 63→  // Set variant to RFC 4122 (bits 6-7 of byte 8)
 64→  hash[8] = (hash[8] & 0x3f) | 0x80;
 65→
 66→  // Format as UUID string (use first 16 bytes of SHA-1)
 67→  const hex = hash.subarray(0, 16).toString("hex");
 68→  return [
 69→    hex.slice(0, 8),
 70→    hex.slice(8, 12),
 71→    hex.slice(12, 16),
 72→    hex.slice(16, 20),
 73→    hex.slice(20, 32),
 74→  ].join("-");
 75→}
 76→
 77→// ---------------------------------------------------------------------------
 78→// Title Truncation
 79→// ---------------------------------------------------------------------------
 80→
 81→export function truncateTitle(text: string, maxLength: number = MAX_TITLE_LENGTH): string {
 82→  if (text.length <= maxLength) return text;
 83→  return text.slice(0, maxLength) + "...";
 84→}
 85→
 86→// ---------------------------------------------------------------------------
 87→// System Prompt Normalization
 88→// ---------------------------------------------------------------------------
 89→
 90→function normalizeSystemPrompt(input: ConversationHashInput): string | undefined {
 91→  if (input.systemPrompt) return input.systemPrompt;
 92→
 93→  if (input.systemPromptBlocks && input.systemPromptBlocks.length > 0) {
 94→    const textBlocks = input.systemPromptBlocks
 95→      .filter((block) => block.type === "text")
 96→      .map((block) => block.text);
 97→    return textBlocks.length > 0 ? textBlocks.join("\n") : undefined;
 98→  }
 99→
100→  return undefined;
101→}
102→
103→// ---------------------------------------------------------------------------
104→// First User Message Extraction
105→// ---------------------------------------------------------------------------
106→
107→function extractFirstUserMessage(
108→  messages: ReadonlyArray<{ role: string; content: string }>,
109→): string | undefined {
110→  const firstUserMsg = messages.find((msg) => msg.role === "user");
