118→/**
119→ * Resolve a deterministic conversation identity from request content.
120→ *
121→ * Returns undefined when either the system prompt or the first user message
122→ * is missing -- these are required to compute a stable hash.
123→ *
124→ * The conversation ID is a UUIDv5 derived from:
125→ *   UUIDv5(BRAIN_PROXY_NAMESPACE, system_prompt + NUL + first_user_message)
126→ *
127→ * The title is the first user message, truncated to ~100 characters.
128→ */
129→export function resolveConversationHash(
130→  input: ConversationHashInput,
131→): ConversationHashResult | undefined {
132→  const systemPrompt = normalizeSystemPrompt(input);
133→  if (!systemPrompt) return undefined;
134→
135→  const firstUserMessage = extractFirstUserMessage(input.messages);
136→  if (!firstUserMessage) return undefined;
137→
138→  const hashContent = systemPrompt + NUL_SEPARATOR + firstUserMessage;
139→  const conversationId = generateUuidV5(BRAIN_PROXY_NAMESPACE, hashContent);
140→  const title = truncateTitle(firstUserMessage);
141→
142→  return { conversationId, title };
143→}
