138→// ---------------------------------------------------------------------------
139→// Path Detection
140→// ---------------------------------------------------------------------------
141→
142→function isCountTokensRequest(pathname: string): boolean {
143→  return pathname.endsWith("/count_tokens");
144→}
145→
146→// ---------------------------------------------------------------------------
147→// SSE Usage Extraction
148→// ---------------------------------------------------------------------------
149→
150→type StreamContext = {
151→  model?: string;
152→  inputTokens: number;
153→  outputTokens: number;
154→  cacheCreationTokens: number;
155→  cacheReadTokens: number;
156→  stopReason?: string;
157→};
158→
159→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
160→  const lines = buffer.split("\n");
161→  const remainder = lines.pop() ?? "";
162→
163→  for (const line of lines) {
164→    if (!line.startsWith("data: ")) continue;
165→    const data = line.slice(6);
166→    if (data === "[DONE]") continue;
167→
168→    try {
169→      const event = JSON.parse(data);
170→
171→      if (event.type === "message_start" && event.message?.usage) {
172→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
173→        ctx.cacheCreationTokens = event.message.usage.cache_creation_input_tokens ?? 0;
174→        ctx.cacheReadTokens = event.message.usage.cache_read_input_tokens ?? 0;
175→        ctx.model = event.message.model ?? ctx.model;
176→      }
177→
178→      if (event.type === "message_delta") {
179→        if (event.usage?.output_tokens) {
180→          ctx.outputTokens = event.usage.output_tokens;
181→        }
182→        if (event.delta?.stop_reason) {
183→          ctx.stopReason = event.delta.stop_reason;
184→        }
185→      }
186→    } catch {
187→      // partial JSON or non-JSON data line — skip
188→    }
189→  }
190→
191→  return remainder;
192→}
193→
194→// ---------------------------------------------------------------------------
195→// Non-Streaming Usage Extraction
196→// ---------------------------------------------------------------------------
197→
198→type NonStreamingResponse = {
199→  model?: string;
200→  usage?: {
201→    input_tokens?: number;
202→    output_tokens?: number;
203→    cache_creation_input_tokens?: number;
204→    cache_read_input_tokens?: number;
205→  };
206→  stop_reason?: string;
207→};
208→
209→function extractNonStreamingUsage(
210→  responseBody: string,
211→  requestModel: string | undefined,
212→  latencyMs: number,
213→  identity: { workspaceId?: string; taskId?: string },
214→  sessionId?: string,
215→  policyDecision?: PolicyDecisionLog,
216→  conversationId?: string,
217→  injectionResult?: InjectionResult,
218→): TraceData | undefined {
219→  try {
220→    const parsed = JSON.parse(responseBody) as NonStreamingResponse;
221→    if (!parsed.usage) return undefined;
222→
223→    const traceData: TraceData = {
224→      model: parsed.model ?? requestModel ?? "unknown",
225→      inputTokens: parsed.usage.input_tokens ?? 0,
226→      outputTokens: parsed.usage.output_tokens ?? 0,
227→      cacheCreationTokens: parsed.usage.cache_creation_input_tokens ?? 0,
228→      cacheReadTokens: parsed.usage.cache_read_input_tokens ?? 0,
229→      stopReason: parsed.stop_reason,
230→      latencyMs,
231→      workspaceId: identity.workspaceId,
232→      sessionId,
233→      taskId: identity.taskId,
234→      policyDecision,
235→      conversationId,
236→    };
237→
238→    // Add intelligence metadata if injection occurred
239→    if (injectionResult) {
240→      (traceData as any).intelligenceMetadata = buildIntelligenceMetadata(injectionResult);
241→    }
242→
243→    // Capture response content (opaque, per ADR-051)
244→    const responseContent = extractResponseContent(responseBody);
245→    if (responseContent) {
246→      (traceData as any).responseContent = responseContent;
247→    }
248→
249→    return traceData;

