255→// ---------------------------------------------------------------------------
256→// Context Candidate Pool Loader (adapter boundary)
257→// ---------------------------------------------------------------------------
258→
259→const DECISION_WEIGHT = 1.0;
260→const LEARNING_WEIGHT = 0.8;
261→const OBSERVATION_WEIGHT = 0.7;
262→
263→async function loadCandidatePool(
264→  surreal: ServerDependencies["surreal"],
265→  workspaceId: string,
266→): Promise<CachedCandidatePool> {
267→  const workspaceRecord = new RecordId("workspace", workspaceId);
268→
269→  type DecisionRow = { id: RecordId; summary: string; embedding?: number[] };
270→  type LearningRow = { id: RecordId; text: string; embedding?: number[] };
271→  type ObservationRow = { id: RecordId; text: string; embedding?: number[] };
272→
273→  // Sequential queries to avoid SurrealDB SDK concurrency issues with
274→  // multiple parallel queries on a single WebSocket connection
275→  const decisionResults = await surreal.query<[DecisionRow[]]>(
276→    `SELECT id, summary, embedding FROM decision WHERE workspace = $ws AND status = 'confirmed' LIMIT 50;`,
277→    { ws: workspaceRecord },
278→  );
279→  const learningResults = await surreal.query<[LearningRow[]]>(
280→    `SELECT id, text, embedding FROM learning WHERE workspace = $ws AND status = 'active' LIMIT 30;`,
281→    { ws: workspaceRecord },
282→  );
283→  const observationResults = await surreal.query<[ObservationRow[]]>(
284→    `SELECT id, text, embedding FROM observation WHERE workspace = $ws AND status = 'open' AND severity IN ['conflict', 'warning'] AND observation_type NOT IN ['proxy_no_policy'] LIMIT 20;`,
285→    { ws: workspaceRecord },
286→  );
287→
288→  function toCandidates<T extends { id: RecordId; embedding?: number[] }>(
289→    rows: T[],
290→    type: CandidateItem["type"],
291→    weight: number,
292→    textFn: (row: T) => string,
293→  ): CandidateItem[] {
294→    return rows.map((row) => ({
295→      id: (row.id as RecordId).id as string,
296→      type,
297→      text: textFn(row),
298→      weight,
299→      embedding: row.embedding,
300→    }));
301→  }
302→
303→  const decisions = toCandidates(decisionResults[0] ?? [], "decision", DECISION_WEIGHT, (d) => d.summary);
304→  const learnings = toCandidates(learningResults[0] ?? [], "learning", LEARNING_WEIGHT, (l) => l.text);
305→  const observations = toCandidates(observationResults[0] ?? [], "observation", OBSERVATION_WEIGHT, (o) => o.text);
306→
307→  return {
308→    decisions,
309→    learnings,
310→    observations,
311→    populatedAt: Date.now(),
312→  };
313→}
314→
315→// ---------------------------------------------------------------------------
316→// Embedding Helper (adapter boundary)
317→// ---------------------------------------------------------------------------
318→
319→async function embedUserMessage(
320→  embeddingModel: ServerDependencies["embeddingModel"],
321→  embeddingDimension: number,
322→  text: string,
323→): Promise<number[] | undefined> {
324→  try {
325→    const { embed } = await import("ai");
326→    const normalized = text.trim();
327→    if (normalized.length === 0) return undefined;
328→
329→    const result = await embed({
330→      model: embeddingModel,
331→      value: normalized,
332→    });
333→
334→    if (result.embedding.length !== embeddingDimension) return undefined;
335→    return result.embedding;
336→  } catch {
337→    return undefined;
338→  }
339→}
