341→// ---------------------------------------------------------------------------
342→// Context Injection Pipeline (orchestrator)
343→// ---------------------------------------------------------------------------
344→
345→type ContextInjectionResult = {
346→  readonly body: string;
347→  readonly injectionResult?: InjectionResult;
348→};
349→
350→async function runContextInjection(
351→  deps: ServerDependencies,
352→  workspaceId: string,
353→  parsedBody: ParsedBody,
354→  originalBody: string,
355→  contextCache: ContextCache,
356→  intelligenceConfig: IntelligenceConfig,
357→): Promise<ContextInjectionResult> {
358→  if (!intelligenceConfig.contextInjectionEnabled) {
359→    return { body: originalBody };
360→  }
361→
362→  // 1. Get or populate candidate pool (with cache)
363→  let pool: CachedCandidatePool;
364→  let fromCache = false;
365→  if (contextCache.has(workspaceId)) {
366→    pool = contextCache.get(workspaceId)!;
367→    fromCache = true;
368→  } else {
369→    pool = await loadCandidatePool(deps.surreal, workspaceId);
370→    contextCache.set(workspaceId, pool);
371→  }
372→
373→  // 2. Check if pool is empty
374→  const allCandidates: ContextCandidate[] = [
375→    ...pool.decisions,
376→    ...pool.learnings,
377→    ...pool.observations,
378→  ];
379→  if (allCandidates.length === 0) {
380→    return { body: originalBody };
381→  }
382→
383→  logInfo("proxy.context_injection.pool_loaded", "Candidate pool loaded", {
384→    workspace_id: workspaceId,
385→    decisions: pool.decisions.length,
386→    learnings: pool.learnings.length,
387→    observations: pool.observations.length,
388→    total: allCandidates.length,
389→    cached: fromCache,
390→  });
391→
392→  // 3. Extract last user message for embedding
393→  const lastUserMessage = [...(parsedBody.messages ?? [])].reverse().find((m) => m.role === "user");
394→  if (!lastUserMessage) {
395→    return { body: originalBody };
396→  }
397→
398→  // 4. Embed last user message
399→  const queryEmbedding = await embedUserMessage(

400→    deps.embeddingModel,
401→    deps.config.embeddingDimension,
402→    lastUserMessage.content,
403→  );
404→
405→  let selectedCandidates;
406→  if (queryEmbedding) {
407→    // 5. Rank candidates by weighted cosine similarity
408→    const ranked = rankCandidates(allCandidates, queryEmbedding);
409→    // 6. Select within token budget
410→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
411→  } else {
412→    // No embedding available -- fall back to all candidates within budget
413→    const ranked = allCandidates.map((c) => ({
414→      id: c.id,
415→      type: c.type,
416→      text: c.text,
417→      score: c.weight,
418→    }));
419→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
420→  }
421→
422→  if (selectedCandidates.length === 0) {
423→    return { body: originalBody };
424→  }
425→
426→  // 7. Build XML block
427→  const brainContextXml = buildBrainContextXml(selectedCandidates);
428→
429→  // 8. Inject into system prompt
430→  const injectionResult = injectBrainContext(parsedBody.system, brainContextXml);
431→
432→  // 9. Build modified request body
433→  const modifiedBody = {
434→    ...parsedBody,
435→    system: injectionResult.system,
436→  };
437→
438→  return {
439→    body: JSON.stringify(modifiedBody),
440→    injectionResult,
441→  };
442→}
443→
444→// ---------------------------------------------------------------------------
445→// Intelligence Metadata Builder (pure)
446→// ---------------------------------------------------------------------------
447→
448→function buildIntelligenceMetadata(injectionResult: InjectionResult) {
449→  return {
450→    brain_context_injected: injectionResult.injected,
451→    brain_context_decisions: injectionResult.decisionsCount,
452→    brain_context_learnings: injectionResult.learningsCount,
453→    brain_context_observations: injectionResult.observationsCount,
454→    brain_context_tokens_est: injectionResult.tokensEstimated,
455→  };
456→}
