  1→/**
  2→ * Anthropic LLM Proxy Route
  3→ *
  4→ * Transparent proxy that forwards requests to Anthropic's Messages API
  5→ * with identity resolution, session tracking, and workspace validation.
  6→ *
  7→ * Pipeline execution order:
  8→ * 1. Identity resolution (from metadata + headers)
  9→ * 2. Session ID resolution (header priority over metadata)
 10→ * 3. Conversation hash (03-01) — deterministic UUIDv5 from content
 11→ * 4. Policy evaluation [future 02-01]
 12→ * 5. Context injection [future 03-02]
 13→ * 6. Request forwarding
 14→ * 7. Async trace capture (01-03) + conversation upsert
 15→ */
 16→import { logInfo, logError, logWarn, elapsedMs } from "../http/observability";
 17→import { jsonResponse } from "../http/response";
 18→import { resolveIdentity } from "./identity-resolver";
 19→import { resolveSessionId, resolveAgentSessionId } from "./session-id-resolver";
 20→import { captureTrace, type TraceData } from "./trace-writer";
 21→import {
 22→  resolveConversationHash,
 23→  type ConversationHashInput,
 24→} from "./conversation-hash-resolver";
 25→import { upsertConversation } from "./conversation-upserter";
 26→import {
 27→  evaluateProxyPolicy,
 28→  type ProxyPolicyDependencies,
 29→  type ProxyPolicyResult,
 30→  type PolicyDecisionLog,
 31→  type SpendCache,
 32→} from "./policy-evaluator";
 33→import {
 34→  createRateLimiterState,
 35→  pruneStaleEntries,
 36→  type RateLimiterState,
 37→} from "./rate-limiter";
 38→import {
 39→  loadIntelligenceConfig,
 40→  type IntelligenceConfig,
 41→} from "./intelligence-config";
 42→import {
 43→  createContextCache,
 44→  type ContextCache,
 45→  type CachedCandidatePool,
 46→  type CandidateItem,
 47→} from "./context-cache";
 48→import {
 49→  rankCandidates,
 50→  selectWithinBudget,
 51→  buildBrainContextXml,
 52→  injectBrainContext,
 53→  type ContextCandidate,
 54→  type InjectionResult,
 55→} from "./context-injector";
 56→import type { ServerDependencies } from "../runtime/types";
 57→import { RecordId } from "surrealdb";
 58→
 59→const FORWARDED_HEADERS = [
 60→  "anthropic-version",
 61→  "anthropic-beta",
 62→  "content-type",
 63→] as const;
 64→
 65→// ---------------------------------------------------------------------------
 66→// Workspace Validation (cached)
 67→// ---------------------------------------------------------------------------
 68→
 69→type WorkspaceCache = Map<string, { valid: boolean; checkedAt: number }>;
 70→
 71→const WORKSPACE_CACHE_TTL_MS = 60_000; // 1 minute
 72→
 73→async function validateWorkspace(
 74→  surreal: ServerDependencies["surreal"],
 75→  workspaceId: string,
 76→  cache: WorkspaceCache,
 77→): Promise<boolean> {
 78→  const cached = cache.get(workspaceId);
 79→  if (cached && Date.now() - cached.checkedAt < WORKSPACE_CACHE_TTL_MS) {
 80→    return cached.valid;
 81→  }
 82→
 83→  try {
 84→    const results = await surreal.query<[Array<{ id: RecordId }>]>(
 85→      `SELECT id FROM $ws;`,
 86→      { ws: new RecordId("workspace", workspaceId) },
 87→    );
 88→    const valid = (results[0]?.length ?? 0) > 0;
 89→    cache.set(workspaceId, { valid, checkedAt: Date.now() });
 90→    return valid;
 91→  } catch {
 92→    cache.set(workspaceId, { valid: false, checkedAt: Date.now() });
 93→    return false;
 94→  }
 95→}
 96→
 97→// ---------------------------------------------------------------------------
 98→// Header Forwarding
 99→// ---------------------------------------------------------------------------
100→
101→function buildUpstreamHeaders(request: Request): Headers {
102→  const headers = new Headers();
103→
104→  for (const name of FORWARDED_HEADERS) {
105→    const value = request.headers.get(name);
106→    if (value) headers.set(name, value);
107→  }
108→
109→  const xApiKey = request.headers.get("x-api-key");
110→  const authHeader = request.headers.get("authorization");
111→  if (xApiKey) headers.set("x-api-key", xApiKey);
112→  if (authHeader) headers.set("authorization", authHeader);
113→
114→  return headers;
115→}
116→
117→// ---------------------------------------------------------------------------
118→// Request Body Parsing
119→// ---------------------------------------------------------------------------
120→
121→type ParsedBody = {
122→  model?: string;
123→  stream?: boolean;
124→  max_tokens?: number;
125→  metadata?: { user_id?: string };
126→  system?: string | Array<{ type: string; text: string }>;
127→  messages?: Array<{ role: string; content: string }>;
128→};
129→
130→function tryParseRequestBody(body: string): ParsedBody | undefined {
131→  try {
132→    return JSON.parse(body) as ParsedBody;
133→  } catch {
134→    return undefined;
135→  }
136→}
137→
138→// ---------------------------------------------------------------------------
139→// Path Detection
140→// ---------------------------------------------------------------------------
141→
142→function isCountTokensRequest(pathname: string): boolean {
143→  return pathname.endsWith("/count_tokens");
144→}
145→
146→// ---------------------------------------------------------------------------
147→// SSE Usage Extraction
148→// ---------------------------------------------------------------------------
149→
150→type StreamContext = {
151→  model?: string;
152→  inputTokens: number;
153→  outputTokens: number;
154→  cacheCreationTokens: number;
155→  cacheReadTokens: number;
156→  stopReason?: string;
157→};
158→
159→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
160→  const lines = buffer.split("\n");
161→  const remainder = lines.pop() ?? "";
162→
163→  for (const line of lines) {
164→    if (!line.startsWith("data: ")) continue;
165→    const data = line.slice(6);
166→    if (data === "[DONE]") continue;
167→
168→    try {
169→      const event = JSON.parse(data);
170→
171→      if (event.type === "message_start" && event.message?.usage) {
172→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
173→        ctx.cacheCreationTokens = event.message.usage.cache_creation_input_tokens ?? 0;
174→        ctx.cacheReadTokens = event.message.usage.cache_read_input_tokens ?? 0;
175→        ctx.model = event.message.model ?? ctx.model;
176→      }
177→
178→      if (event.type === "message_delta") {
179→        if (event.usage?.output_tokens) {
180→          ctx.outputTokens = event.usage.output_tokens;
181→        }
182→        if (event.delta?.stop_reason) {
183→          ctx.stopReason = event.delta.stop_reason;
184→        }
185→      }
186→    } catch {
187→      // partial JSON or non-JSON data line — skip
188→    }
189→  }
190→
191→  return remainder;
192→}
193→
194→// ---------------------------------------------------------------------------
195→// Non-Streaming Usage Extraction
196→// ---------------------------------------------------------------------------
197→
198→type NonStreamingResponse = {
199→  model?: string;
200→  usage?: {
201→    input_tokens?: number;
202→    output_tokens?: number;
203→    cache_creation_input_tokens?: number;
204→    cache_read_input_tokens?: number;
205→  };
206→  stop_reason?: string;
207→};
208→
209→function extractNonStreamingUsage(
210→  responseBody: string,
211→  requestModel: string | undefined,
212→  latencyMs: number,
213→  identity: { workspaceId?: string; taskId?: string },
214→  sessionId?: string,
215→  policyDecision?: PolicyDecisionLog,
216→  conversationId?: string,
217→  injectionResult?: InjectionResult,
218→): TraceData | undefined {
219→  try {
220→    const parsed = JSON.parse(responseBody) as NonStreamingResponse;
221→    if (!parsed.usage) return undefined;
222→
223→    const traceData: TraceData = {
224→      model: parsed.model ?? requestModel ?? "unknown",
225→      inputTokens: parsed.usage.input_tokens ?? 0,
226→      outputTokens: parsed.usage.output_tokens ?? 0,
227→      cacheCreationTokens: parsed.usage.cache_creation_input_tokens ?? 0,
228→      cacheReadTokens: parsed.usage.cache_read_input_tokens ?? 0,
229→      stopReason: parsed.stop_reason,
230→      latencyMs,
231→      workspaceId: identity.workspaceId,
232→      sessionId,
233→      taskId: identity.taskId,
234→      policyDecision,
235→      conversationId,
236→    };
237→
238→    // Add intelligence metadata if injection occurred
239→    if (injectionResult) {
240→      (traceData as any).intelligenceMetadata = buildIntelligenceMetadata(injectionResult);
241→    }
242→
243→    // Capture response content (opaque, per ADR-051)
244→    const responseContent = extractResponseContent(responseBody);
245→    if (responseContent) {
246→      (traceData as any).responseContent = responseContent;
247→    }
248→
249→    return traceData;
250→  } catch {
251→    return undefined;
252→  }
253→}
254→
255→// ---------------------------------------------------------------------------
256→// Context Candidate Pool Loader (adapter boundary)
257→// ---------------------------------------------------------------------------
258→
259→const DECISION_WEIGHT = 1.0;
260→const LEARNING_WEIGHT = 0.8;
261→const OBSERVATION_WEIGHT = 0.7;
262→
263→async function loadCandidatePool(
264→  surreal: ServerDependencies["surreal"],
265→  workspaceId: string,
266→): Promise<CachedCandidatePool> {
267→  const workspaceRecord = new RecordId("workspace", workspaceId);
268→
269→  type DecisionRow = { id: RecordId; summary: string; embedding?: number[] };
270→  type LearningRow = { id: RecordId; text: string; embedding?: number[] };
271→  type ObservationRow = { id: RecordId; text: string; embedding?: number[] };
272→
273→  // Sequential queries to avoid SurrealDB SDK concurrency issues with
274→  // multiple parallel queries on a single WebSocket connection
275→  const decisionResults = await surreal.query<[DecisionRow[]]>(
276→    `SELECT id, summary, embedding FROM decision WHERE workspace = $ws AND status = 'confirmed' LIMIT 50;`,
277→    { ws: workspaceRecord },
278→  );
279→  const learningResults = await surreal.query<[LearningRow[]]>(
280→    `SELECT id, text, embedding FROM learning WHERE workspace = $ws AND status = 'active' LIMIT 30;`,
281→    { ws: workspaceRecord },
282→  );
283→  const observationResults = await surreal.query<[ObservationRow[]]>(
284→    `SELECT id, text, embedding FROM observation WHERE workspace = $ws AND status = 'open' AND severity IN ['conflict', 'warning'] AND observation_type NOT IN ['proxy_no_policy'] LIMIT 20;`,
285→    { ws: workspaceRecord },
286→  );
287→
288→  function toCandidates<T extends { id: RecordId; embedding?: number[] }>(
289→    rows: T[],
290→    type: CandidateItem["type"],
291→    weight: number,
292→    textFn: (row: T) => string,
293→  ): CandidateItem[] {
294→    return rows.map((row) => ({
295→      id: (row.id as RecordId).id as string,
296→      type,
297→      text: textFn(row),
298→      weight,
299→      embedding: row.embedding,
300→    }));
301→  }
302→
303→  const decisions = toCandidates(decisionResults[0] ?? [], "decision", DECISION_WEIGHT, (d) => d.summary);
304→  const learnings = toCandidates(learningResults[0] ?? [], "learning", LEARNING_WEIGHT, (l) => l.text);
305→  const observations = toCandidates(observationResults[0] ?? [], "observation", OBSERVATION_WEIGHT, (o) => o.text);
306→
307→  return {
308→    decisions,
309→    learnings,
310→    observations,
311→    populatedAt: Date.now(),
312→  };
313→}
314→
315→// ---------------------------------------------------------------------------
316→// Embedding Helper (adapter boundary)
317→// ---------------------------------------------------------------------------
318→
319→async function embedUserMessage(
320→  embeddingModel: ServerDependencies["embeddingModel"],
321→  embeddingDimension: number,
322→  text: string,
323→): Promise<number[] | undefined> {
324→  try {
325→    const { embed } = await import("ai");
326→    const normalized = text.trim();
327→    if (normalized.length === 0) return undefined;
328→
329→    const result = await embed({
330→      model: embeddingModel,
331→      value: normalized,
332→    });
333→
334→    if (result.embedding.length !== embeddingDimension) return undefined;
335→    return result.embedding;
336→  } catch {
337→    return undefined;
338→  }
339→}
340→
341→// ---------------------------------------------------------------------------
342→// Context Injection Pipeline (orchestrator)
343→// ---------------------------------------------------------------------------
344→
345→type ContextInjectionResult = {
346→  readonly body: string;
347→  readonly injectionResult?: InjectionResult;
348→};
349→
350→async function runContextInjection(
351→  deps: ServerDependencies,
352→  workspaceId: string,
353→  parsedBody: ParsedBody,
354→  originalBody: string,
355→  contextCache: ContextCache,
356→  intelligenceConfig: IntelligenceConfig,
357→): Promise<ContextInjectionResult> {
358→  if (!intelligenceConfig.contextInjectionEnabled) {
359→    return { body: originalBody };
360→  }
361→
362→  // 1. Get or populate candidate pool (with cache)
363→  let pool: CachedCandidatePool;
364→  let fromCache = false;
365→  if (contextCache.has(workspaceId)) {
366→    pool = contextCache.get(workspaceId)!;
367→    fromCache = true;
368→  } else {
369→    pool = await loadCandidatePool(deps.surreal, workspaceId);
370→    contextCache.set(workspaceId, pool);
371→  }
372→
373→  // 2. Check if pool is empty
374→  const allCandidates: ContextCandidate[] = [
375→    ...pool.decisions,
376→    ...pool.learnings,
377→    ...pool.observations,
378→  ];
379→  if (allCandidates.length === 0) {
380→    return { body: originalBody };
381→  }
382→
383→  logInfo("proxy.context_injection.pool_loaded", "Candidate pool loaded", {
384→    workspace_id: workspaceId,
385→    decisions: pool.decisions.length,
386→    learnings: pool.learnings.length,
387→    observations: pool.observations.length,
388→    total: allCandidates.length,
389→    cached: fromCache,
390→  });
391→
392→  // 3. Extract last user message for embedding
393→  const lastUserMessage = [...(parsedBody.messages ?? [])].reverse().find((m) => m.role === "user");
394→  if (!lastUserMessage) {
395→    return { body: originalBody };
396→  }
397→
398→  // 4. Embed last user message
399→  const queryEmbedding = await embedUserMessage(
400→    deps.embeddingModel,
401→    deps.config.embeddingDimension,
402→    lastUserMessage.content,
403→  );
404→
405→  let selectedCandidates;
406→  if (queryEmbedding) {
407→    // 5. Rank candidates by weighted cosine similarity
408→    const ranked = rankCandidates(allCandidates, queryEmbedding);
409→    // 6. Select within token budget
410→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
411→  } else {
412→    // No embedding available -- fall back to all candidates within budget
413→    const ranked = allCandidates.map((c) => ({
414→      id: c.id,
415→      type: c.type,
416→      text: c.text,
417→      score: c.weight,
418→    }));
419→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
420→  }
421→
422→  if (selectedCandidates.length === 0) {
423→    return { body: originalBody };
424→  }
425→
426→  // 7. Build XML block
427→  const brainContextXml = buildBrainContextXml(selectedCandidates);
428→
429→  // 8. Inject into system prompt
430→  const injectionResult = injectBrainContext(parsedBody.system, brainContextXml);
431→
432→  // 9. Build modified request body
433→  const modifiedBody = {
434→    ...parsedBody,
435→    system: injectionResult.system,
436→  };
437→
438→  return {
439→    body: JSON.stringify(modifiedBody),
440→    injectionResult,
441→  };
442→}
443→
444→// ---------------------------------------------------------------------------
445→// Intelligence Metadata Builder (pure)
446→// ---------------------------------------------------------------------------
447→
448→function buildIntelligenceMetadata(injectionResult: InjectionResult) {
449→  return {
450→    brain_context_injected: injectionResult.injected,
451→    brain_context_decisions: injectionResult.decisionsCount,
452→    brain_context_learnings: injectionResult.learningsCount,
453→    brain_context_observations: injectionResult.observationsCount,
454→    brain_context_tokens_est: injectionResult.tokensEstimated,
455→  };
456→}
457→
458→// ---------------------------------------------------------------------------
459→// Non-Streaming Response Content Extraction (for trace output)
460→// ---------------------------------------------------------------------------
461→
462→type ResponseContent = {
463→  content_blocks: Array<{ type: string; text?: string; id?: string; name?: string; input?: unknown }>;
464→  stop_reason: string;
465→  usage: {
466→    input_tokens: number;
467→    output_tokens: number;
468→    cache_creation_tokens?: number;
469→    cache_read_tokens?: number;
470→  };
471→};
472→
473→function extractResponseContent(responseBody: string): ResponseContent | undefined {
474→  try {
475→    const parsed = JSON.parse(responseBody);
476→    if (!parsed.content || !parsed.usage) return undefined;
477→
478→    return {
479→      content_blocks: parsed.content,
480→      stop_reason: parsed.stop_reason ?? "end_turn",
481→      usage: {
482→        input_tokens: parsed.usage.input_tokens ?? 0,
483→        output_tokens: parsed.usage.output_tokens ?? 0,
484→        cache_creation_tokens: parsed.usage.cache_creation_input_tokens,
485→        cache_read_tokens: parsed.usage.cache_read_input_tokens,
486→      },
487→    };
488→  } catch {
489→    return undefined;
490→  }
491→}
492→
493→// ---------------------------------------------------------------------------
494→// Policy Denial Response Builder
495→// ---------------------------------------------------------------------------
496→
497→function buildPolicyDenialResponse(
498→  result: Exclude<ProxyPolicyResult, { decision: "allow" }>,
499→): Response {
500→  if (result.decision === "deny_rate_limit") {
501→    return new Response(JSON.stringify(result.body), {
502→      status: result.status,
503→      headers: {
504→        "Content-Type": "application/json",
505→        "Retry-After": String(result.retryAfterSeconds),
506→        "Access-Control-Allow-Origin": "*",
507→      },
508→    });
509→  }
510→  return jsonResponse(result.body, result.status);
511→}
512→
513→// ---------------------------------------------------------------------------
514→// Streaming Trace Builder
515→// ---------------------------------------------------------------------------
516→
517→function buildStreamingTraceData(
518→  streamCtx: StreamContext,
519→  latencyMs: number,
520→  identitySignals: import("./identity-resolver").IdentitySignals,
521→  effectiveSessionId: string | undefined,
522→  policyDecision: PolicyDecisionLog | undefined,
523→  conversationId: string | undefined,
524→  injectionResult: InjectionResult | undefined,
525→): TraceData {
526→  return {
527→    model: streamCtx.model!,
528→    inputTokens: streamCtx.inputTokens,
529→    outputTokens: streamCtx.outputTokens,
530→    cacheCreationTokens: streamCtx.cacheCreationTokens,
531→    cacheReadTokens: streamCtx.cacheReadTokens,
532→    stopReason: streamCtx.stopReason,
533→    latencyMs,
534→    workspaceId: identitySignals.workspaceId,
535→    sessionId: effectiveSessionId,
536→    taskId: identitySignals.taskId,
537→    policyDecision,
538→    conversationId,
539→    ...(injectionResult ? {
540→      intelligenceMetadata: buildIntelligenceMetadata(injectionResult),
541→    } : {}),
542→  };
543→}
544→
545→// ---------------------------------------------------------------------------
546→// Handler Factory
547→// ---------------------------------------------------------------------------
548→
549→export function createAnthropicProxyHandler(
550→  deps: ServerDependencies,
551→): (request: Request) => Promise<Response> {
552→  const workspaceCache: WorkspaceCache = new Map();
553→  const rateLimiterState: RateLimiterState = createRateLimiterState();
554→  const spendCache: SpendCache = new Map();
555→  const noPolicyWarnedWorkspaces = new Set<string>();
556→  const contextCache: ContextCache = createContextCache(300); // default TTL, overridden per-workspace
557→
558→  // Periodic pruning of stale rate limiter entries to prevent unbounded Map growth.
559→  // unref() ensures this interval does not keep the process alive on shutdown.
560→  const pruneInterval = setInterval(
561→    () => pruneStaleEntries(rateLimiterState, Date.now()),
562→    5 * 60 * 1000,
563→  );
564→  pruneInterval.unref();
565→
566→  const anthropicApiUrl = deps.config.anthropicApiUrl;
567→
568→  return async (request: Request): Promise<Response> => {
569→    const startedAt = performance.now();
570→    const url = new URL(request.url);
571→    const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
572→    const upstreamUrl = `${anthropicApiUrl}${upstreamPath}`;
573→    const isCountTokens = isCountTokensRequest(url.pathname);
574→
575→    // --- Step 1: Parse request body (malformed body forwarded as-is) ---
576→    const body = await request.text();
577→    const parsed = tryParseRequestBody(body);
578→    const isStreaming = parsed?.stream === true;
579→
580→    // --- Step 2: Identity resolution ---
581→    const identitySignals = resolveIdentity({
582→      metadataUserId: parsed?.metadata?.user_id,
583→      workspaceHeader: request.headers.get("X-Brain-Workspace") ?? undefined,
584→      taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
585→      agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
586→      sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
587→    });
588→
589→    // --- Step 3: Session ID resolution ---
590→    // resolveSessionId returns either the header PK or the external Claude Code
591→    // session UUID. Resolve to the actual agent_session PK via DB lookup.
592→    const rawSessionId = resolveSessionId(identitySignals);
593→    const effectiveSessionId = rawSessionId
594→      ? await resolveAgentSessionId(deps.surreal, rawSessionId)
595→      : undefined;
596→
597→    // --- Step 3.5: Conversation hash resolution (pure) ---
598→    const conversationHashInput: ConversationHashInput = {
599→      systemPrompt: typeof parsed?.system === "string" ? parsed.system : undefined,
600→      systemPromptBlocks: Array.isArray(parsed?.system) ? parsed.system : undefined,
601→      messages: parsed?.messages ?? [],
602→    };
603→    const conversationHash = resolveConversationHash(conversationHashInput);
604→
605→    // --- Conversation upsert (async, non-blocking) ---
606→    let conversationId: string | undefined;
607→    if (conversationHash && identitySignals.workspaceId) {
608→      try {
609→        const conversationRecord = await upsertConversation(
610→          {
611→            conversationId: conversationHash.conversationId,
612→            workspaceId: identitySignals.workspaceId,
613→            title: conversationHash.title,
614→          },
615→          { surreal: deps.surreal },
616→        );
617→        if (conversationRecord) {
618→          conversationId = conversationHash.conversationId;
619→        }
620→      } catch (error) {
621→        logWarn("proxy.anthropic.conversation_upsert_failed", "Conversation upsert failed — continuing without conversation link", {
622→          error: String(error),
623→        });
624→      }
625→    }
626→
627→    // --- Workspace validation (non-blocking) ---
628→    if (identitySignals.workspaceId) {
629→      const isValid = await validateWorkspace(
630→        deps.surreal,
631→        identitySignals.workspaceId,
632→        workspaceCache,
633→      );
634→      if (!isValid) {
635→        logWarn("proxy.anthropic.invalid_workspace", "Workspace not found in database", {
636→          workspaceId: identitySignals.workspaceId,
637→        });
638→      }
639→    }
640→
641→    // --- Step 4: Policy evaluation ---
642→    let policyResult: ProxyPolicyResult | undefined;
643→    if (parsed?.model && !isCountTokens) {
644→      const policyDeps: ProxyPolicyDependencies = {
645→        surreal: deps.surreal,
646→        inflight: deps.inflight,
647→        rateLimiterState,
648→        spendCache,
649→      };
650→
651→      policyResult = await evaluateProxyPolicy(
652→        {
653→          workspaceId: identitySignals.workspaceId ?? "",
654→          agentType: identitySignals.agentType,
655→          model: parsed.model,
656→        },
657→        policyDeps,
658→        noPolicyWarnedWorkspaces,
659→      );
660→
661→      if (policyResult.decision !== "allow") {
662→        return buildPolicyDenialResponse(policyResult);
663→      }
664→    }
665→
666→    // --- Step 5: Context injection (fail-open) ---
667→    let effectiveBody = body;
668→    let injectionResult: InjectionResult | undefined;
669→
670→    if (parsed && identitySignals.workspaceId && !isCountTokens) {
671→      try {
672→        const intelligenceConfig = await loadIntelligenceConfig(deps.surreal, identitySignals.workspaceId);
673→        const contextResult = await runContextInjection(
674→          deps,
675→          identitySignals.workspaceId,
676→          parsed,
677→          body,
678→          contextCache,
679→          intelligenceConfig,
680→        );
681→        effectiveBody = contextResult.body;
682→        injectionResult = contextResult.injectionResult;
683→        if (intelligenceConfig.contextInjectionEnabled) {
684→          logInfo("proxy.context_injection.result", "Context injection completed", {
685→            workspace_id: identitySignals.workspaceId,
686→            injected: injectionResult?.injected ?? false,
687→            decisions: injectionResult?.decisionsCount ?? 0,
688→            learnings: injectionResult?.learningsCount ?? 0,
689→            observations: injectionResult?.observationsCount ?? 0,
690→          });
691→        }
692→      } catch (error) {
693→        // Fail-open: log warning and continue with original body
694→        logWarn("proxy.context_injection.failed", "Context injection failed, forwarding original request", {
695→          workspace_id: identitySignals.workspaceId,
696→          error: String(error),
697→        });
698→      }
699→    }
700→
701→    // --- API key validation ---
702→    const hasApiKey = request.headers.has("x-api-key");
703→    const hasAuthHeader = request.headers.has("authorization");
704→    if (!hasApiKey && !hasAuthHeader) {
705→      return jsonResponse(
706→        { error: "unauthorized", message: "Missing x-api-key or authorization header" },
707→        401,
708→      );
709→    }
710→
711→    // --- Build identity context for logging ---
712→    const identityContext = {
713→      user_hash: identitySignals.userHash,
714→      account_id: identitySignals.accountId,
715→      session_id: effectiveSessionId,
716→      workspace_id: identitySignals.workspaceId,
717→      task_id: identitySignals.taskId,
718→      agent_type: identitySignals.agentType,
719→      is_count_tokens: isCountTokens || undefined,
720→    };
721→
722→    logInfo("proxy.anthropic.request", "Forwarding to Anthropic", {
723→      method: request.method,
724→      url: upstreamUrl,
725→      ...identityContext,
726→    });
727→
728→    // --- Build policy decision for audit trail ---
729→    const policyDecision: PolicyDecisionLog | undefined = policyResult
730→      ? {
731→          decision: "pass",
732→          policy_refs: policyResult.decision === "allow" ? policyResult.policyIds : [],
733→          timestamp: new Date().toISOString(),
734→        }
735→      : undefined;
736→
737→    // --- Step 6: Request forwarding ---
738→    const upstreamHeaders = buildUpstreamHeaders(request);
739→
740→    let upstream: Response;
741→    try {
742→      upstream = await fetch(upstreamUrl, {
743→        method: request.method,
744→        headers: upstreamHeaders,
745→        body: request.method !== "GET" ? effectiveBody : undefined,
746→      });
747→    } catch (error) {
748→      logError("proxy.anthropic.upstream_error", "Failed to reach Anthropic API", error);
749→      return jsonResponse({ error: "upstream_unreachable", source: "proxy" }, 502);
750→    }
751→
752→    // --- Non-streaming response ---
753→    if (!isStreaming) {
754→      const responseBody = await upstream.text();
755→      const latencyMs = elapsedMs(startedAt);
756→
757→      logInfo("proxy.anthropic.response", "Anthropic response", {
758→        status: upstream.status,
759→        latency_ms: latencyMs,
760→        ...identityContext,
761→      });
762→
763→      // Async trace capture for non-streaming (skip count_tokens)
764→      if (!isCountTokens && upstream.status >= 200 && upstream.status < 300) {
765→        const traceData = extractNonStreamingUsage(responseBody, parsed?.model, latencyMs, identitySignals, effectiveSessionId, policyDecision, conversationId, injectionResult);
766→        if (traceData) {
767→          deps.inflight.track(
768→            captureTrace(traceData, { surreal: deps.surreal }).catch(() => undefined),
769→          );
770→        }
771→      }
772→
773→      return new Response(responseBody, {
774→        status: upstream.status,
775→        headers: {
776→          "Content-Type": upstream.headers.get("content-type") ?? "application/json",
777→          "Access-Control-Allow-Origin": "*",
778→        },
779→      });
780→    }
781→
782→    // --- Streaming: pipe SSE events through ---
783→    const { readable, writable } = new TransformStream<Uint8Array>();
784→    const writer = writable.getWriter();
785→    const reader = upstream.body!.getReader();
786→    const decoder = new TextDecoder();
787→
788→    const streamContext: StreamContext = {
789→      model: parsed?.model,
790→      inputTokens: 0,
791→      outputTokens: 0,
792→      cacheCreationTokens: 0,
793→      cacheReadTokens: 0,
794→      stopReason: undefined,
795→    };
796→
797→    (async () => {
798→      try {
799→        let buffer = "";
800→        while (true) {
801→          const { done, value } = await reader.read();
802→          if (done) break;
803→
804→          await writer.write(value);
805→
806→          buffer += decoder.decode(value, { stream: true });
807→          buffer = extractSSEUsage(buffer, streamContext);
808→        }
809→      } catch (error) {
810→        logError("proxy.anthropic.stream_error", "SSE relay error", error);
811→      } finally {
812→        await writer.close();
813→
814→        const latencyMs = elapsedMs(startedAt);
815→
816→        logInfo("proxy.anthropic.response", "Anthropic stream complete", {
817→          model: streamContext.model,
818→          input_tokens: streamContext.inputTokens,
819→          output_tokens: streamContext.outputTokens,
820→          cache_creation_tokens: streamContext.cacheCreationTokens,
821→          cache_read_tokens: streamContext.cacheReadTokens,
822→          stop_reason: streamContext.stopReason,
823→          latency_ms: latencyMs,
824→          ...identityContext,
825→        });
826→
827→        // Async trace capture for streaming (skip count_tokens)
828→        if (!isCountTokens && streamContext.model) {
829→          const traceData = buildStreamingTraceData(
830→            streamContext, latencyMs, identitySignals,
831→            effectiveSessionId, policyDecision, conversationId, injectionResult,
832→          );
833→          deps.inflight.track(
834→            captureTrace(traceData, { surreal: deps.surreal }).catch(() => undefined),
835→          );
836→        }
837→      }
838→    })();
839→
840→    return new Response(readable, {
841→      status: upstream.status,
842→      headers: {
843→        "Content-Type": "text/event-stream",
844→        "Cache-Control": "no-cache",
845→        "Connection": "keep-alive",
846→        "X-Accel-Buffering": "no",
847→        "Access-Control-Allow-Origin": "*",
848→      },
849→    });
850→  };
851→}
