35→/**
36→ * Parse Claude Code's metadata.user_id format:
37→ * "user_<hash>_account_<uuid>_session_<uuid>"
38→ *
39→ * Returns extracted fields, or treats the entire string as an opaque user hash
40→ * when it doesn't match the expected pattern.
41→ */
42→function parseMetadataUserId(userId?: string): {
43→  userHash?: string;
44→  accountId?: string;
45→  sessionId?: string;
46→} {
47→  if (!userId) return {};
48→
49→  const match = userId.match(
50→    /^user_([\w-]+)_account_([\w-]+)_session_([\w-]+)$/,
51→  );
52→
53→  if (!match) return { userHash: userId };
54→
55→  return {
56→    userHash: match[1],
57→    accountId: match[2],
58→    sessionId: match[3],
59→  };
60→}
61→
62→/**
63→ * Resolve identity signals from request metadata and headers.
64→ *
65→ * Combines Claude Code metadata.user_id parsing with X-Brain-* headers
66→ * to produce a complete identity picture. Missing signals degrade
67→ * gracefully — each field is optional.
68→ */
69→export function resolveIdentity(input: IdentityInput): IdentitySignals {
70→  const parsed = parseMetadataUserId(input.metadataUserId);
71→
72→  return {
73→    userHash: parsed.userHash,
74→    accountId: parsed.accountId,
75→    sessionId: parsed.sessionId,
76→    sessionHeaderId: input.sessionHeader,
77→    workspaceId: input.workspaceHeader,
78→    taskId: input.taskHeader,
79→    agentType: input.agentTypeHeader,
80→  };
81→}
