493→// ---------------------------------------------------------------------------
494→// Policy Denial Response Builder
495→// ---------------------------------------------------------------------------
496→
497→function buildPolicyDenialResponse(
498→  result: Exclude<ProxyPolicyResult, { decision: "allow" }>,
499→): Response {
500→  if (result.decision === "deny_rate_limit") {
501→    return new Response(JSON.stringify(result.body), {
502→      status: result.status,
503→      headers: {
504→        "Content-Type": "application/json",
505→        "Retry-After": String(result.retryAfterSeconds),
506→        "Access-Control-Allow-Origin": "*",
507→      },
508→    });
509→  }
510→  return jsonResponse(result.body, result.status);
511→}
