545→// ---------------------------------------------------------------------------
546→// Handler Factory
547→// ---------------------------------------------------------------------------
548→
549→export function createAnthropicProxyHandler(
550→  deps: ServerDependencies,
551→): (request: Request) => Promise<Response> {
552→  const workspaceCache: WorkspaceCache = new Map();
553→  const rateLimiterState: RateLimiterState = createRateLimiterState();
554→  const spendCache: SpendCache = new Map();
555→  const noPolicyWarnedWorkspaces = new Set<string>();
556→  const contextCache: ContextCache = createContextCache(300); // default TTL, overridden per-workspace
557→
558→  // Periodic pruning of stale rate limiter entries to prevent unbounded Map growth.
559→  // unref() ensures this interval does not keep the process alive on shutdown.
560→  const pruneInterval = setInterval(
561→    () => pruneStaleEntries(rateLimiterState, Date.now()),
562→    5 * 60 * 1000,
563→  );
564→  pruneInterval.unref();
565→
566→  const anthropicApiUrl = deps.config.anthropicApiUrl;
567→
568→  return async (request: Request): Promise<Response> => {
569→    const startedAt = performance.now();
570→    const url = new URL(request.url);
571→    const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
572→    const upstreamUrl = `${anthropicApiUrl}${upstreamPath}`;
573→    const isCountTokens = isCountTokensRequest(url.pathname);
574→
575→    // --- Step 1: Parse request body (malformed body forwarded as-is) ---
576→    const body = await request.text();
577→    const parsed = tryParseRequestBody(body);
578→    const isStreaming = parsed?.stream === true;
579→
580→    // --- Step 2: Identity resolution ---
581→    const identitySignals = resolveIdentity({
582→      metadataUserId: parsed?.metadata?.user_id,
583→      workspaceHeader: request.headers.get("X-Brain-Workspace") ?? undefined,
584→      taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
585→      agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
586→      sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
587→    });
588→
589→    // --- Step 3: Session ID resolution ---
590→    // resolveSessionId returns either the header PK or the external Claude Code
591→    // session UUID. Resolve to the actual agent_session PK via DB lookup.
592→    const rawSessionId = resolveSessionId(identitySignals);
593→    const effectiveSessionId = rawSessionId
594→      ? await resolveAgentSessionId(deps.surreal, rawSessionId)
595→      : undefined;
596→
597→    // --- Step 3.5: Conversation hash resolution (pure) ---
598→    const conversationHashInput: ConversationHashInput = {
599→      systemPrompt: typeof parsed?.system === "string" ? parsed.system : undefined,
600→      systemPromptBlocks: Array.isArray(parsed?.system) ? parsed.system : undefined,
601→      messages: parsed?.messages ?? [],
602→    };
603→    const conversationHash = resolveConversationHash(conversationHashInput);
604→
605→    // --- Conversation upsert (async, non-blocking) ---
606→    let conversationId: string | undefined;
607→    if (conversationHash && identitySignals.workspaceId) {
608→      try {
609→        const conversationRecord = await upsertConversation(
610→          {
611→            conversationId: conversationHash.conversationId,
612→            workspaceId: identitySignals.workspaceId,
613→            title: conversationHash.title,
614→          },
615→          { surreal: deps.surreal },
616→        );
617→        if (conversationRecord) {
618→          conversationId = conversationHash.conversationId;
619→        }
620→      } catch (error) {
621→        logWarn("proxy.anthropic.conversation_upsert_failed", "Conversation upsert failed — continuing without conversation link", {
622→          error: String(error),
623→        });
624→      }
625→    }
626→
627→    // --- Workspace validation (non-blocking) ---
628→    if (identitySignals.workspaceId) {
629→      const isValid = await validateWorkspace(
630→        deps.surreal,
631→        identitySignals.workspaceId,
632→        workspaceCache,
633→      );
634→      if (!isValid) {
635→        logWarn("proxy.anthropic.invalid_workspace", "Workspace not found in database", {
636→          workspaceId: identitySignals.workspaceId,
637→        });
638→      }
639→    }
640→
641→    // --- Step 4: Policy evaluation ---
642→    let policyResult: ProxyPolicyResult | undefined;
643→    if (parsed?.model && !isCountTokens) {
644→      const policyDeps: ProxyPolicyDependencies = {
645→        surreal: deps.surreal,
646→        inflight: deps.inflight,
647→        rateLimiterState,
648→        spendCache,
649→      };
650→
651→      policyResult = await evaluateProxyPolicy(
652→        {
653→          workspaceId: identitySignals.workspaceId ?? "",
654→          agentType: identitySignals.agentType,
655→          model: parsed.model,
656→        },
657→        policyDeps,
658→        noPolicyWarnedWorkspaces,
659→      );
660→
661→      if (policyResult.decision !== "allow") {
662→        return buildPolicyDenialResponse(policyResult);
663→      }
664→    }
665→
666→    // --- Step 5: Context injection (fail-open) ---
667→    let effectiveBody = body;
668→    let injectionResult: InjectionResult | undefined;
669→
670→    if (parsed && identitySignals.workspaceId && !isCountTokens) {
671→      try {
672→        const intelligenceConfig = await loadIntelligenceConfig(deps.surreal, identitySignals.workspaceId);
673→        const contextResult = await runContextInjection(
674→          deps,
675→          identitySignals.workspaceId,
676→          parsed,
677→          body,
678→          contextCache,
679→          intelligenceConfig,
680→        );
681→        effectiveBody = contextResult.body;
682→        injectionResult = contextResult.injectionResult;
683→        if (intelligenceConfig.contextInjectionEnabled) {
684→          logInfo("proxy.context_injection.result", "Context injection completed", {
685→            workspace_id: identitySignals.workspaceId,
686→            injected: injectionResult?.injected ?? false,
687→            decisions: injectionResult?.decisionsCount ?? 0,
688→            learnings: injectionResult?.learningsCount ?? 0,
689→            observations: injectionResult?.observationsCount ?? 0,
690→          });
691→        }
692→      } catch (error) {
693→        // Fail-open: log warning and continue with original body
694→        logWarn("proxy.context_injection.failed", "Context injection failed, forwarding original request", {
695→          workspace_id: identitySignals.workspaceId,
696→          error: String(error),
697→        });
698→      }
699→    }
700→
701→    // --- API key validation ---
702→    const hasApiKey = request.headers.has("x-api-key");
703→    const hasAuthHeader = request.headers.has("authorization");
704→    if (!hasApiKey && !hasAuthHeader) {
705→      return jsonResponse(
706→        { error: "unauthorized", message: "Missing x-api-key or authorization header" },
707→        401,
708→      );
709→    }
710→
711→    // --- Build identity context for logging ---
712→    const identityContext = {
713→      user_hash: identitySignals.userHash,
714→      account_id: identitySignals.accountId,
715→      session_id: effectiveSessionId,
716→      workspace_id: identitySignals.workspaceId,
717→      task_id: identitySignals.taskId,
718→      agent_type: identitySignals.agentType,
719→      is_count_tokens: isCountTokens || undefined,
720→    };
721→
722→    logInfo("proxy.anthropic.request", "Forwarding to Anthropic", {
723→      method: request.method,
724→      url: upstreamUrl,
725→      ...identityContext,
726→    });
727→
728→    // --- Build policy decision for audit trail ---
729→    const policyDecision: PolicyDecisionLog | undefined = policyResult
730→      ? {
731→          decision: "pass",
732→          policy_refs: policyResult.decision === "allow" ? policyResult.policyIds : [],
733→          timestamp: new Date().toISOString(),
734→        }
735→      : undefined;
736→
737→    // --- Step 6: Request forwarding ---
738→    const upstreamHeaders = buildUpstreamHeaders(request);
739→
740→    let upstream: Response;
741→    try {
742→      upstream = await fetch(upstreamUrl, {
743→        method: request.method,
744→        headers: upstreamHeaders,
745→        body: request.method !== "GET" ? effectiveBody : undefined,
746→      });
747→    } catch (error) {
748→      logError("proxy.anthropic.upstream_error", "Failed to reach Anthropic API", error);
749→      return jsonResponse({ error: "upstream_unreachable", source: "proxy" }, 502);
750→    }
751→
752→    // --- Non-streaming response ---
753→    if (!isStreaming) {
754→      const responseBody = await upstream.text();
755→      const latencyMs = elapsedMs(startedAt);
756→
757→      logInfo("proxy.anthropic.response", "Anthropic response", {
758→        status: upstream.status,
759→        latency_ms: latencyMs,
760→        ...identityContext,
761→      });
762→
763→      // Async trace capture for non-streaming (skip count_tokens)
764→      if (!isCountTokens && upstream.status >= 200 && upstream.status < 300) {
765→        const traceData = extractNonStreamingUsage(responseBody, parsed?.model, latencyMs, identitySignals, effectiveSessionId, policyDecision, conversationId, injectionResult);
766→        if (traceData) {
767→          deps.inflight.track(
768→            captureTrace(traceData, { surreal: deps.surreal }).catch(() => undefined),
769→          );
770→        }
771→      }
772→
773→      return new Response(responseBody, {
774→        status: upstream.status,
775→        headers: {
776→          "Content-Type": upstream.headers.get("content-type") ?? "application/json",
777→          "Access-Control-Allow-Origin": "*",
778→        },
779→      });
780→    }
781→
782→    // --- Streaming: pipe SSE events through ---
783→    const { readable, writable } = new TransformStream<Uint8Array>();
784→    const writer = writable.getWriter();
785→    const reader = upstream.body!.getReader();
786→    const decoder = new TextDecoder();
787→
788→    const streamContext: StreamContext = {
789→      model: parsed?.model,
790→      inputTokens: 0,
791→      outputTokens: 0,
792→      cacheCreationTokens: 0,
793→      cacheReadTokens: 0,
794→      stopReason: undefined,
795→    };
796→
797→    (async () => {
798→      try {
799→        let buffer = "";
800→        while (true) {
801→          const { done, value } = await reader.read();
802→          if (done) break;
803→
804→          await writer.write(value);
805→
806→          buffer += decoder.decode(value, { stream: true });
807→          buffer = extractSSEUsage(buffer, streamContext);
808→        }
809→      } catch (error) {
810→        logError("proxy.anthropic.stream_error", "SSE relay error", error);
811→      } finally {
812→        await writer.close();
813→
814→        const latencyMs = elapsedMs(startedAt);
815→
816→        logInfo("proxy.anthropic.response", "Anthropic stream complete", {
817→          model: streamContext.model,
818→          input_tokens: streamContext.inputTokens,
819→          output_tokens: streamContext.outputTokens,
820→          cache_creation_tokens: streamContext.cacheCreationTokens,
821→          cache_read_tokens: streamContext.cacheReadTokens,
822→          stop_reason: streamContext.stopReason,
823→          latency_ms: latencyMs,
824→          ...identityContext,
825→        });
826→
827→        // Async trace capture for streaming (skip count_tokens)
828→        if (!isCountTokens && streamContext.model) {
829→          const traceData = buildStreamingTraceData(
830→            streamContext, latencyMs, identitySignals,
831→            effectiveSessionId, policyDecision, conversationId, injectionResult,
832→          );
833→          deps.inflight.track(
834→            captureTrace(traceData, { surreal: deps.surreal }).catch(() => undefined),
835→          );
836→        }
837→      }
838→    })();
839→
840→    return new Response(readable, {
841→      status: upstream.status,
842→      headers: {
843→        "Content-Type": "text/event-stream",
844→        "Cache-Control": "no-cache",
845→        "Connection": "keep-alive",
846→        "X-Accel-Buffering": "no",
847→        "Access-Control-Allow-Origin": "*",
848→      },
849→    });
850→  };
851→}
