  1→/**
  2→ * Unit Tests: Conversation Hash Resolver (Pure Function)
  3→ *
  4→ * The conversation hash resolver derives a deterministic conversation ID
  5→ * from request content using UUIDv5(NAMESPACE, system_prompt + NUL + first_user_message).
  6→ *
  7→ * Properties tested:
  8→ * - Deterministic: same inputs always produce the same conversation ID
  9→ * - Distinct: different system prompts or different first messages produce different IDs
 10→ * - Format: output is a valid UUIDv5 string
 11→ * - Graceful absence: missing system prompt or missing first user message returns undefined
 12→ * - Title truncation: title is truncated to ~100 characters
 13→ */
 14→import { describe, expect, it } from "bun:test";
 15→import {
 16→  resolveConversationHash,
 17→  truncateTitle,
 18→  type ConversationHashInput,
 19→  type ConversationHashResult,
 20→} from "../../app/src/server/proxy/conversation-hash-resolver";
 21→
 22→// ---------------------------------------------------------------------------
 23→// Determinism: same inputs produce same output
 24→// ---------------------------------------------------------------------------
 25→describe("resolveConversationHash determinism", () => {
 26→  it("produces the same conversation ID for identical system prompt and first user message", () => {
 27→    const input: ConversationHashInput = {
 28→      systemPrompt: "You are a helpful assistant.",
 29→      messages: [{ role: "user", content: "Hello world" }],
 30→    };
 31→
 32→    const result1 = resolveConversationHash(input);
 33→    const result2 = resolveConversationHash(input);
 34→
 35→    expect(result1).toBeDefined();
 36→    expect(result2).toBeDefined();
 37→    expect(result1!.conversationId).toBe(result2!.conversationId);
 38→  });
 39→
 40→  it("produces the same ID regardless of subsequent messages (uses only first user message)", () => {
 41→    const input1: ConversationHashInput = {
 42→      systemPrompt: "You are a TypeScript expert.",
 43→      messages: [{ role: "user", content: "How do I use generics?" }],
 44→    };
 45→
 46→    const input2: ConversationHashInput = {
 47→      systemPrompt: "You are a TypeScript expert.",
 48→      messages: [
 49→        { role: "user", content: "How do I use generics?" },
 50→        { role: "assistant", content: "Here is how..." },
 51→        { role: "user", content: "Show me an example" },
 52→      ],
 53→    };
 54→
 55→    const result1 = resolveConversationHash(input1);
 56→    const result2 = resolveConversationHash(input2);
 57→
 58→    expect(result1!.conversationId).toBe(result2!.conversationId);
 59→  });
 60→});
 61→
 62→// ---------------------------------------------------------------------------
 63→// Distinctness: different inputs produce different outputs
 64→// ---------------------------------------------------------------------------
 65→describe("resolveConversationHash distinctness", () => {
 66→  it("produces different IDs for different system prompts with same user message", () => {
 67→    const result1 = resolveConversationHash({
 68→      systemPrompt: "You are a Python developer.",
 69→      messages: [{ role: "user", content: "Help me write code" }],
 70→    });
 71→
 72→    const result2 = resolveConversationHash({
 73→      systemPrompt: "You are a Rust developer.",
 74→      messages: [{ role: "user", content: "Help me write code" }],
 75→    });
 76→
 77→    expect(result1!.conversationId).not.toBe(result2!.conversationId);
 78→  });
 79→
 80→  it("produces different IDs for same system prompt with different user messages", () => {
 81→    const result1 = resolveConversationHash({
 82→      systemPrompt: "You are a helpful assistant.",
 83→      messages: [{ role: "user", content: "Write a function" }],
 84→    });
 85→
 86→    const result2 = resolveConversationHash({
 87→      systemPrompt: "You are a helpful assistant.",
 88→      messages: [{ role: "user", content: "Write a class" }],
